if (index($canonical_filepath, $canonical_log_dir) != 0) {
    print h1('Error');
    print p('Access denied: Path traversal detected.');
    print end_html();
    exit;
}

if (!-e $filepath) {
    print h1('Error');
    print p("Log file '$filename' not found.");
    print end_html();
    exit;
}

if (!-f $filepath) {
    print h1('Error');
    print p("'$filename' is not a regular file.");
    print end_html();
